import{_ as r,o as t,c as a,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const p="/images/vision-pro/Zuck.png",n="/images/vision-pro/headset-600x337.jpg",i="/images/vision-pro/appsinroom.png",s="/images/vision-pro/timavatar.png",l="/images/vision-pro/uncannyvalley-600x324.png",h="/images/vision-pro/Jules-Office.jpg",m="/images/vision-pro/Jules-Mt-Hood.jpg",c="/images/vision-pro/Jules-apps.png",u="/images/vision-pro/iphone-os1.jpeg",g="/images/vision-pro/S-Curves-1.png",f="/images/vision-pro/S-Curves-2.png",w="/images/vision-pro/S-Curves-3.png",b="/images/vision-pro/Scale-1.png",_="/images/vision-pro/pinit_fg_en_rect_gray_20.png",S=JSON.parse('{"title":"All My Thoughts After 40 Hours in the Vision Pro — Wait But Why","description":"","frontmatter":{"title":"All My Thoughts After 40 Hours in the Vision Pro — Wait But Why","titleZh":"戴 Vision Pro 40 小时后的全部感想","date":"2024-02-09T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2024/02/vision-pro.html","slug":"vision-pro"},"headers":[],"relativePath":"posts/vision-pro.md","filePath":"posts/vision-pro.md","lastUpdated":1782886257000}'),V={name:"posts/vision-pro.md"};function d(k,e,P,v,y,A){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="戴-vision-pro-40-小时后的全部感想-·-all-my-thoughts-after-40-hours-in-the-vision-pro-—-wait-but-why" tabindex="-1">戴 Vision Pro 40 小时后的全部感想 · All My Thoughts After 40 Hours in the Vision Pro — Wait But Why <a class="header-anchor" href="#戴-vision-pro-40-小时后的全部感想-·-all-my-thoughts-after-40-hours-in-the-vision-pro-—-wait-but-why" aria-label="Permalink to &quot;戴 Vision Pro 40 小时后的全部感想 · All My Thoughts After 40 Hours in the Vision Pro — Wait But Why&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2024/02/vision-pro.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2024/02/vision-pro.html</a> · 2024-02-09</p></blockquote><p>我正在夏威夷一座 3048 米高的山顶上,通过一块 9 米宽的屏幕写这篇文章;地点是奥斯汀的一家咖啡店,我坐在一张桌子旁,基本可以确定周围的人正在偷拍我发给朋友,好一起骂我是个混蛋。过去这一周,生活变得很诡异。</p><p>我通往哈莱阿卡拉盾状火山奥斯汀咖啡店的旅程,始于 30 多年前的 1990 年。当时我父母带我去了波士顿海港世贸中心的一个叫做「虚拟现实展」的东西。我站在一个小圆台上,工作人员递给我一把塑料枪,把一个大头显套在我头上。突然,我就置身于某个卡通世界里,穿着军装,手里握着一把真枪。旁边圆台上的那个人也在里面——也是卡通形象,也拿着枪。一通笨拙的挥舞和射击之后,他们就把我踢下来,轮到下一位排队的人。</p><p>我不久前刚读过《神奇的收费亭 (The Phantom Tollbooth)》,书里一个现实世界的小孩穿越了一道魔法门槛,进入了卡通世界。这感觉就是那样。我想要更多。</p><p>然后 VR 消失了 25 年。在整个 90 年代和 2000 年代,「虚拟现实」是一个被遗忘的梦——一个很酷但从没实现的概念。但在 2010 年代中期,VR 意外地卷土重来。20 岁的帕尔默·拉基 (Palmer Luckey) 那个用胶带粘起来的头显原型,打动了足够多的投资人,Oculus 因此成了一家真正的公司。2014 年,Facebook 收购了 Oculus。Google 和 Sony 也纷纷入局。一切终于要发生了。</p><p>2016 年,我决定写一篇关于 VR 革命的文章。我跑遍了硅谷,采访 Google 和 Facebook 的人,想把 VR 的来龙去脉挖个透。我甚至还和马克·扎克伯格 (Mark Zuckerberg) 坐下来聊了聊。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/Zuck.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>我把所有东西都体验了一遍。太震撼了。VR 即将统治世界。而我,将会是那个告诉所有人的人。</p><p>然后两件事发生了:</p><ol><li>VR 没有统治世界。</li><li>我没写 VR 文章,因为我掉进了一个长达六年的<a href="https://waitbutwhy.com/whatsourproblem" target="_blank" rel="noreferrer">写书</a>大坑。</li></ol><p>从我那个书坑的坑底,我一直在关注这个故事。在 Facebook 2016 年的开发者大会上,扎克伯格演示了一款新的、极其前沿的「独立式、由内而外 (standalone, inside out)」头显。在那之前,VR 有两种做法:第一种是廉价头显,可能用你的手机当屏幕,能做原始的头部动作追踪,但没法看到周围环境。第二种是墙上装外部传感器,头显通过线缆连接到一台高性能 PC。「独立式」意味着新头显把电脑装进了里面,不需要线缆。「由内而外」意味着头显自己能看到周围的房间,所以不需要外部传感器。在 2016 年,这只是个原型。三年后,Facebook 推出了 Oculus Quest。</p><p>2020 年,新冠疫情期间,我和其他人一样闲得蛋疼没事干,就给自己买了个 Quest 2。真的太棒了。我爱它。它成了我每天写完东西之后的奖励项目。我做 <a href="https://www.tiltbrush.com/" target="_blank" rel="noreferrer">3D 艺术</a>。我 <a href="https://www.meta.com/experiences/2134272053250863/?ranking_trace=0_2134272053250863_SKYLINEWEBQUESTSEARCH_1vKvJ1edv2vQxMeJK" target="_blank" rel="noreferrer">和鲸鱼一起游泳</a>。我去 <a href="https://vacationsimulatorgame.com/" target="_blank" rel="noreferrer">卡通式度假</a>。我通过 <a href="https://www.meta.com/experiences/2448060205267927/" target="_blank" rel="noreferrer">切音乐块</a> 来锻炼身体。我通关了 <a href="https://www.meta.com/experiences/2718107161580827/" target="_blank" rel="noreferrer">Trover</a>。</p><p>然后,不知道为啥,我就不玩了。我真的说不上来为什么。我真的很喜欢待在 Quest 2 里。最近我把它翻出来给朋友们演示,他们惊掉下巴,提醒了我这东西有多牛。它就是没能<em>勾住</em>我。也许是因为它是单人的。我没有玩 VR 的朋友,所以没人陪我玩。也许是因为麻烦。虽然只是一点点,但给头显充电、戴上、划定活动边界<a href="#footnote-1-10470">1</a>,还是比拿起手机麻烦得多。也许我的快乐比我意识到的更依赖于新鲜感。</p><p>不只是我。所有人第一次试 VR 都会被震撼到,但它似乎很难长期把人留住。经过 2010 年代中期的那波炒作大浪之后,VR 退回到了亚文化的角落里。</p><p>问题在于:VR 这个概念是不是有什么致命缺陷,导致它永远无法实现大众普及?还是说我们离 VR 像电脑和智能手机那样冲上平流层只差一个引爆点?</p><h3 id="苹果登场" tabindex="-1"><strong>苹果登场</strong> <a class="header-anchor" href="#苹果登场" aria-label="Permalink to &quot;**苹果登场**&quot;">​</a></h3><p>每个人都记得自己听说肯尼迪遇刺、人类登月、或飞机撞进双子塔时人在哪里。而我记得自己看到史蒂夫·乔布斯 (Steve Jobs) <a href="https://www.youtube.com/watch?v=VQKMoT-6XSg&amp;ab_channel=ProtectstarInc." target="_blank" rel="noreferrer">发布第一代 iPhone</a> 时人在哪里。</p><p>我并不是一直都喜欢苹果的。我家的第一台电脑是 Apple 2GS。但后来,和很多早期苹果电脑用户一样,我变成了 PC 派。我大学时用的是 IBM ThinkPad,觉得用苹果的那些人很烦。</p><p>然后乔布斯回归苹果,开始「让苹果再次伟大」。大学毕业后我走上了作曲的路,不得不入手了一台 2004 年的 PowerBook G4。熟悉了界面之后(<em>为啥他妈的没有开始按钮?</em>),我意识到 Mac 简直太棒了,从此我就成了一个讨人厌的苹果党。但直到 2007 年,我才变成一个真正的<em>狂热粉丝</em>。</p><p>在那场发布会上,当乔布斯做出世界上第一个「滑动解锁」时,观众发出了 <a href="https://youtu.be/VQKMoT-6XSg?si=_ruGaoE1NWaLBrjC&amp;t=933" target="_blank" rel="noreferrer">清晰可闻的惊叹</a>。一分钟后,他在手机的「iPod」应用里调出艺术家列表,<a href="https://youtu.be/VQKMoT-6XSg?si=WXikR3ntj4j3EXd-&amp;t=972" target="_blank" rel="noreferrer">问道</a>:「那么,我怎么滚动查看我的艺术家列表呢?我只要用手指一滑就行了。」又是一阵惊叹。今天如此稀松平常的东西,17 年前竟然能让人下巴掉下来,想想真是奇怪。</p><p>看那场发布会时的感觉,我以前有过。5 岁时第一次在朋友家玩任天堂时有过 (<em>按下这个按钮就能让电视上的东西动起来??</em>)。90 年代初朋友教我发电子邮件时有过 (<em>在你的电脑上打点字,按个按钮,它就出现在我的电脑上??</em>)。第一次试驾特斯拉时也有过 (<em>这车加速起来怎么这么未来感?</em>)。</p><p>我已经学会从这些「我操」时刻里读出很多含义了。大多数情况下,它们之后会有一整个新行业席卷全球——比如智能手机、电子游戏、互联网、电动车革命。</p><p>2023 年 6 月,苹果<a href="https://www.youtube.com/watch?v=GYkq9Rgoj8E" target="_blank" rel="noreferrer">发布了</a>传闻已久的 VR——抱歉,<a href="https://www.techradar.com/computing/software/apple-tells-developers-not-to-use-virtual-reality-when-talking-about-vision-pro" target="_blank" rel="noreferrer"><em>空间计算 (spatial computing)</em></a>——头显:Vision Pro。</p><p>我看了发布会,但感觉跟 2007 年那次不太一样。首先,过去我对 VR 兴奋过好几次,最后都失望了。其次,不像亲自演示 iPhone,在 2D 屏幕上看 VR 演示根本没法让你体会到它真正是什么样。哦对,还有,它卖 <em>3500 美元</em>。我当年很爽快地掏了 600 美元买第一代 iPhone。但 3500 美元?为一个未来几年会大幅改进 (还会降价) 的 V1 产品?我明明已经有 Meta Quest 了?算了。我可能是果粉,但我不是傻子。理智的成年人显然应该再等等。然后预订一开放,我在第一分钟就下单了。</p><p>这周一早上,我去 Apple Store,第一次把 Vision Pro 戴在我这张傻子脸上。店员带我做了个演示。然后它就来了:「我操」时刻。</p><p>但这个「我操」时刻带着一个星号。我在 1990 年和 2016 年玩 VR 时都经历过完整的「我操」时刻,而这两次恰恰是「『我操』时刻是某个行业即将爆炸的确凿预兆」这条规律的显著例外。这次会不同吗,还是历史会重演?</p><p>我知道的是,是时候写一篇 VR 的文章了。我想在这周大家都对 Vision Pro 兴奋的时候发。但我不想在自己还没<em>大量</em>使用之前就写,这样我不仅能体验蜜月期,也能体验用到彻底腻烦是什么感觉。</p><p>计划很清晰。我回到家,告诉我老婆,这一周我会彻底无视她和我们的宝宝,然后连续四天每天戴着头显 12 个小时。我现在是周四下午在写这篇,已经积累了超过 40 小时。以下是我的想法。</p><h2 id="vision-pro-v1" tabindex="-1"><strong>Vision Pro,V1</strong> <a class="header-anchor" href="#vision-pro-v1" aria-label="Permalink to &quot;**Vision Pro,V1**&quot;">​</a></h2><p>任何 VR 系统都有三个组成部分:硬件、操作系统、应用。我们逐个来说。</p><h3 id="硬件" tabindex="-1"><strong>硬件</strong> <a class="header-anchor" href="#硬件" aria-label="Permalink to &quot;**硬件**&quot;">​</a></h3><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/headset.jpg" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>Apple Vision Pro (AVP)<a href="#footnote2-1-10470">1</a> 很重——比 Meta 的 Quest 3(515 克)重得不少(650 克)。它自带一条花哨的头带,戴起来很方便,用一个小旋钮拧紧。棒极了。持续了 12 分钟。然后它开始虐我的脸。带着 3500 个懊悔,我换上了它附带的另一条头带,这条带子多了一个绕过头顶的环,谢天谢地,因为这条<em>好太多了</em>——好到令我震惊的是,即便戴了一整天,摘下来的那一刻我也没有感受到那种「啊——」的极乐解脱。至少目前看来,它似乎只比长时间戴罩耳式耳机稍微不舒服一点点。这可能不适用于每个人,但我戴着它一次都没有感到恶心。</p><p>这不代表戴它就没什么糟糕的地方。「视野」并不好,意思是你余光本该看到的地方是又厚又黑的墙,这挺扫兴的。我很难想象它对眼睛能好到哪里去。而且没办法回避一个事实:当房间里还有其他人时,你会觉得自己像个傻叉。</p><p>有一个外接电池包,通过一根线连到头显上,通常我放在口袋里。电池能撑大约三小时,但你可以给电池插上电让它永远续航,就像一台电池只能用三小时的电脑一样。(你经常会把它和电脑配合使用,这样一来就不成问题,因为你可以把电池插到电脑上。)</p><p>戴上头显时,它会执行 AVP 版的 Face ID:扫描你的虹膜。整个过程无缝而且非常未来感十足。然后,你看到的就是戴上头显之前看到的那个世界。<a href="https://www.youtube.com/watch?v=86Gy035z_KA&amp;ab_channel=MarquesBrownlee" target="_blank" rel="noreferrer">很多</a> <a href="https://www.youtube.com/watch?v=n7hJlyVDEc8&amp;ab_channel=CleoAbram" target="_blank" rel="noreferrer">评</a> <a href="https://daringfireball.net/2024/01/the_vision_pro" target="_blank" rel="noreferrer">测者</a> 都对 AVP 的「透视 (pass-through)」能力赞叹不已,我一戴上就明白为什么了。虽然并不完美,但<em>几乎</em>就像你戴着一副透明的浮潜面镜。头显本身其实是不透明的——外部的摄像头把外界画面传输到内部的屏幕上。但屏幕好到不行、延迟低到不行,以至于它真的看起来就是透明的。然后它还做了另一件远没那么成功的事:让头显从外面看起来也是透明的,用内部的摄像头把你的眼睛投射到头显的正面。目标是,当你戴着头显跟别人说话时,双方都感觉你戴着一副透明的浮潜面镜。但至少在 V1 版本里,眼睛显示的效果远不如<a href="https://waitbutwhy.com/wp-content/uploads/2024/02/applead-eyes.png" target="_blank" rel="noreferrer">宣传</a>的那么好。</p><p>内部的屏幕通过一种叫「注视点渲染 (foveated rendering)」的聪明做法来省电——也就是说,只有你正在看的那个精确位置是完美聚焦的,画面的其他部分则是低分辨率的。你真正的眼睛就是这么干的,所以你的余光才是模糊的。如果你看看我做的这个<a href="https://x.com/waitbutwhy/status/1755000159698612346?s=20" target="_blank" rel="noreferrer">视频串流 (viewcast)</a>,你会发现大部分画面都是糊的(清晰的那块正好是我录制时在看的地方)——但作为戴着头显的人,我看到的一直都是完美清晰的画面。</p><p>Vision Pro 处理音频的方式也很酷。以前在手机或电脑上我只有两个声音选项:用喇叭放,所有人都听得到;或者戴耳机,谁都听不到。AVP 的喇叭介于两者之间。喇叭(音质很棒)很小,就在你耳朵正上方,紧挨着你的人能听到你听的东西,但隔壁房间的人听不到。所以在咖啡店或飞机上,你还是需要戴耳机,但我很多工作都是在我们家里那个开着门的办公室做的,能既不戴耳机、<em>又</em>不打扰隔壁房间的人,感觉挺好。</p><h3 id="操作系统" tabindex="-1"><strong>操作系统</strong> <a class="header-anchor" href="#操作系统" aria-label="Permalink to &quot;**操作系统**&quot;">​</a></h3><p>这是我那个「我操」时刻里最「我操」的部分。苹果是简洁直观界面的王者。2007 年那些惊呼声,一部分正是来自 iPhone 界面的那种<em>自然感</em>。你把页面往上推来向下滚动,就像你在现实中会做的那样。你用两根手指捏合来缩放。就像魔法一样。AVP 的界面之所以让人倒吸凉气,也是同样的原因。它的主要手势,我一直管它叫「眼捏 (eye pinch)」。</p><p>当你按下头显顶部的按钮,你的应用就会弹出来,悬浮在你面前的房间里,看起来跟房间里其他任何物体一样真实。它们固定在空间中。你可以直接走过去,细节惊人。<a href="#footnote2-2-10470">2</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/appsinroom.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>Vision Pro 的眼动追踪好到离谱。它<em>精确地</em>知道你在看哪里。所以你要选一个应用,只需要看着它,然后把拇指和食指捏在一起。你的手不用抬起来做这个动作,只要放在头显能看到的地方就行。看广告的时候,这看起来可能挺烦的,但实际上跟在智能手机上打开一个应用一样简单直观。</p><p>不管你在做什么,眼捏都相当于用手指触摸智能手机屏幕。要滚动的话,看向窗口任意位置,捏一下,把手向上移动。要移动窗口,看向窗口下方的小横条,捏住,把它移到你想放的地方。要调整窗口大小,看向窗口的角,捏一下,再调整。</p><p>正如 John Gruber 在他的<a href="https://daringfireball.net/2024/01/the_vision_pro" target="_blank" rel="noreferrer">评测</a>中所说:</p><p><em>VisionOS 里那套基础交互模型,感觉未来所有 VR/AR 头显都会照抄,就像现在所有台式电脑都学 Mac,所有手机和平板都学 iPhone 一样。等到那一天,有些人会说,它们当然都得这样工作啊,不然还能怎么工作?但个人电脑在 Mac 之前是没有指点式图形界面的,手机在 iPhone 之前也没有「整个就是一块大触摸屏」这种界面。今天没有任何其他头显有「盯着目标看一眼,然后食指拇指一捏」这样的交互。我怀疑再过几年,它们全都会这么干。</em></p><p>再说说另一件事:你眼前看到的整个空间,都是可以用来干活的桌面。用电脑的时候,我习惯把应用叠起来,然后在它们之间切换。要么就把几个竖窗口并排放。而在 AVP 里,我可以在正前方放一个 8 英尺宽的窗口,左右两侧再各放一个,再在它们<em>上方</em>的天空里挂几个。然后如果我起身走到另一个房间,窗口全都会原地不动,乖乖等我回来。如果我想换个工作地点,只要按住头显按钮,整套布局就会「嗖」地跳到新位置。这一切比我描述得酷得多,所以我做了个视频给你看看它是怎么工作的:</p><p>视频里你会注意到,我经常拧头显上的数字表冠,在「完全处于现实」「部分处于现实」和「完全处于虚拟环境」之间来回滑。这操作爽得离谱。它也顺便提醒了大家:AR 和 VR<a href="#footnote-2-10470">2</a> 作为两个独立品类这件事,已经是过去时了。在 Vision Pro、Quest 3、以及未来任何一款头显上,你可以 100% 处于真实世界(屏幕上什么都没有,你就像戴了个浮潜面罩),你可以基本处于真实世界,只是厨房桌上多了个虚拟<a href="https://youtu.be/-dJu9VyIw64?si=CXyrl8KvUcYQ5uYZ&amp;t=449" target="_blank" rel="noreferrer">棋盘</a>,或者有只小小的虚拟蝴蝶在你旁边飞。你可以处于半现实半虚拟的状态——比如玩游戏时,身边的墙上<a href="https://youtu.be/-dJu9VyIw64?si=N85diDS1-4EDe5-1&amp;t=476" target="_blank" rel="noreferrer">开出一扇扇传送门</a>。或者你可以彻底沉进虚拟世界。</p><h3 id="应用" tabindex="-1"><strong>应用</strong> <a class="header-anchor" href="#应用" aria-label="Permalink to &quot;**应用**&quot;">​</a></h3><p>空间计算应用可以分成很多类——生产力、娱乐、社交、游戏、创作、健身——今天要玩其中大多数,你需要一台 Meta Quest 或者别的非 Apple 头显。AVP 上确实有那么屈指可数的几个惊艳应用,但那更像是「能做成什么样」的抽样展示,而不是一个真正的应用商店。</p><p>这次体验中最能体现「除了 VR 头显以外你绝对没法在任何地方做这件事」的,是他们那个沉浸式娱乐的小型试吃菜单。头显上的娱乐内容按沉浸程度分布在一个光谱上。沉浸感最弱的,是在虚拟空间(比如月球或巨型影院)的大银幕上看一部普通电影。那些你错过的、大家都说要在大银幕上看才过瘾的电影——现在你可以在大银幕上看了。</p><p>再往上是那种画面是普通矩形、但看起来是 3D 的电影——就像我们以前戴那种傻乎乎的纸眼镜看的那种,只是好得多得多。有时候会有惊喜,某个东西会从屏幕里<em>跑出来</em>,飞过空中,或者站在你和屏幕之间的地板上。AVP 里就自带一个这样的内容——「与恐龙相遇 (Encounter Dinosaurs)」——非常好玩。</p><p>最后是完全沉浸,场景完全把你包围起来,你真的感觉自己身在其中。这种与其说是「娱乐」,不如说是「体验」。去年我近距离亲眼看过犀牛。然后这周,我做了一个 Vision Pro 的体验,内容就是近距离和犀牛待在一起。这两次体验<em>非常</em>相似。还有一个体验让你坐在爱丽西亚·凯斯 (Alicia Keys) 的排练现场,她站在离你两英尺的地方唱几首歌。你可以看她一会儿,然后转头看看鼓手或键盘手在干什么——就跟你真的在现场时会做的一样。</p><p>照片和视频也很酷。你拍全景照片时,手机会在空中划出一个 C 形弧线——但在平面手机屏幕上,结果只是一张平面照片。在 AVP 里,全景照片是 C 形的,跟你实际拍摄时的形状一样。C 形环绕在你身边,我很快就发现,这比平面版本更能唤起记忆。你还可以把头显变成相机,拍摄照片和视频,两者都是沉浸式的。之后你在头显里回看时,它们是 3D 的,把你直接送回了当时的场景。</p><p>然后就是那个臭名昭著的 Vision Pro 数字化身 (avatar)。做法是把头显翻过来,让它从不同角度给你拍照。之后你 FaceTime 别人时,你的化身会模仿你做出的任何面部表情。这是我的:</p><p><img src="'+s+'" alt=""></p><p>我第一个测试对象是我老婆,她立刻惊恐地倒吸一口凉气,说我「脑袋里有一双恐怖谷小蛇眼在滴溜溜转」,鬼知道这他妈是什么意思。</p><p>她说的这个恐怖谷 (uncanny valley) 是这个:<a href="#footnote2-3-10470">3</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/uncannyvalley.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>意思是,我们喜欢那些有点像人的脸,也喜欢完全像人的脸,但我们<em>讨厌</em>那种几乎像人、但又不完全像人的脸。差一点点就够得上人类的那种脸,会让我们集体起鸡皮疙瘩。</p><p>虚拟化身 (avatar) 以前烂得要命。后来变好了一些。现在它们好到一头栽进了恐怖谷。这在通往完美化身的路上总归是要发生的,而那个时刻就是现在。</p><p>为了亲自测试一下,我用 FaceTime 打给了我的朋友 <a href="https://www.tiktok.com/@julesterpak" target="_blank" rel="noreferrer">Jules Terpak</a>,她也有一台 Vision Pro。我先把她放在这张桌子的对面,我们就用彼此的恐怖谷脸相互对视了几分钟。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/Jules-Office.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>有一件事非常酷:当我把她的窗口移到桌子的另一个座位时,她的声音也跟着移到了那个位置。我们的结论是这个活动其实相比 FaceTime 并没有升级,但如果人数超过两个,它可能会让人感觉大家真的围坐在一张桌子旁,这会比群组 FaceTime 或 Zoom 通话感觉好。</p><p>然后我们把场景切换到了胡德山 (Mount Hood)。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/Jules-Mt-Hood.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>这就更有一种我们真的一起在某个地方玩耍的感觉,这种效果 FaceTime 是给不了的。</p><p>当我们一起进入各种应用之后,那种「一起做某件事」的感觉更强了 —— 这种体验通常没法在不见面的情况下拥有。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/Jules-apps.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>目前的形式还非常粗糙,但这是我们在 2030 年代大概率会不停做的事情的雏形版本。这是人类几个世纪以来征服远距离这一使命的下一步。先是有了信件,然后是电话,再然后是手机<a href="#footnote-3-10470">3</a>和视频通话。下一步就是 VR 一起玩。</p><p>到目前为止,我在 Vision Pro 里花时间最多的事,就是我平时本来就在做的事——只不过是 AVP 版本的。当你戴着头显坐在电脑前,你可以把电脑屏幕作为一个巨大的虚拟窗口打开(你依然用平时的键盘和触控板操作)。你平时工作的那块屏幕现在变得大得多、大得多。它的移动性也强得多。我平时不在沙发上工作,因为我更喜欢大显示器而不是笔记本屏幕。这周,我在沙发上对着一块 100 英寸的显示器工作了很久。我平时也不会平躺在床上工作,因为笔记本屏幕不会正好在我上方。这周我这么干了,把屏幕挂在天花板上。我在门廊上干了点活,又在一棵树下干了点。有时我能看到周围的房间,只是里面漂着一块大屏幕。其他时候,我完全进入沉浸模式,在山顶、沙丘或月球上写作。正如我在开头提到的,我 <a href="https://waitbutwhy.com/wp-content/uploads/2024/02/timincafe-scaled.jpeg" target="_blank" rel="noreferrer">此刻</a> 就在咖啡馆里用 AVP,这官方认证是 <a href="https://x.com/waitbutwhy/status/1755672453999710482?s=20" target="_blank" rel="noreferrer">很尴尬的</a>。</p><p>出于某种奇怪的原因,你(目前还)不能打开多个桌面,但你<em>可以</em>把桌面上的一些东西作为独立的 App 在单独的窗口里打开。有一个 AVP 版的 iMessage App,所以我关掉了桌面上的 iMessage,在旁边的窗口里打开它。我经常和 Alicia(WBW 的“很多事情经理”)远程协作,平时把她放在屏幕角落的一个小窗口里。现在,她有了自己独立的窗口。如果我愿意咬牙把 Chrome 换成 Safari,我还可以把我的资料查阅和网页浏览也从桌面上拽出来。最终结果就是,一块小小的、无法移动的电脑屏幕,被一大堆屏幕组成的马赛克墙给取代了,代价不过是脸上整天挂着个浮潜面罩而已。感觉有点像你走进了自己的电脑屏幕里,走进了那幅漂亮的壁纸风景中,置身于一个个窗口之间。非常超现实。我这整篇文章都是在头显里写的,而且我发现自己比平时更享受写作——也更专注。</p><h3 id="我的总体感受" tabindex="-1"><strong>我的总体感受</strong> <a class="header-anchor" href="#我的总体感受" aria-label="Permalink to &quot;**我的总体感受**&quot;">​</a></h3><p>我对 Vision Pro 的感受,最好的形容方式是一种奇怪的组合:彻底被震撼到,同时又略感失望。</p><p>那个神奇的交互界面、那些巨大的屏幕、那些沉浸式体验——它们酷得难以想象,令人敬畏。感觉像是提前偷看了 2030 年代。</p><p>但几天之后,我发现自己在想:“就……这样?”我把那少数几个沉浸式体验都玩过了,玩了那少得可怜的游戏选集里的几款,看了一堆我的全景照片,试了试虚拟形象 FaceTime——而目前,Vision Pro 里就没剩下多少其他能做的事了。</p><p>第一代 iPhone 也让我陷入了同样的震撼与无聊的混合情绪。手机和我度过了一段火热的蜜月期,但等到界面的新鲜感消退,它能提供的也就那 16 个实用 App。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/iphone-os1.jpeg" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>当时还没有 App Store,通话动不动就掉线,蜂窝网络(通话时还没法用)慢得让人痛苦。那时的 iPhone 还不是改变世界的设备。它只是一颗种子,一颗最终会长成改变世界的设备的种子。</p><p>如果把技术的故事拉远来看,你通常会看到一条大大的指数曲线。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/S-Curves-1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>但如果凑近了看,你会发现这条曲线其实是波浪状的,由一段段 S 曲线组成。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/S-Curves-2.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>第一代 iPhone 之所以意义重大,是因为它开启了一条新的 S 曲线。投资者有了新的砸钱地方。开发者有了新的投入精力的地方。创作者有了新的挥洒才华的地方。当数百万人时投入到这项集体的人类工程中,接下来的五年就是一场创新与兴奋的旋风。苹果的发布会成了所有科技爱好者的必看节目,因为从 iPhone 1 到 3G 到 3GS 到 4 到 4S 再到 5,每一次跨越都是硬件和软件上的巨大飞跃。这就是 S 曲线陡峭的那一段。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/S-Curves-3.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>然后,发布会变得无聊了。变化都是渐进式的。苹果停止了创新,开始了打磨。这正好赶上蒂姆·库克 (Tim Cook) 接手,但这不是他的错。S 曲线的陡峭段不会永远持续,而公司往往在行业成熟后、在 S 曲线顶部那段无聊的时期收获最大的回报。</p><p>也许 VR 迟迟没有起飞,并不是因为 VR 本身有什么根本性问题。也许是因为在过去十年里,我们一直在 VR 的 S 曲线的最早期挣扎——那是一段缓慢的时期,基础技术还在被研究和搭建。我的 Vision Pro 有一堆缺点——太贵、太重、有点卡顿、功能有限、虚拟形象诡异——因为处在 S 曲线底部的产品就是这个样子。在这个阶段,消费级产品还没准备好大规模普及。但正是在这些年里取得的突破,为曲线上爆发式的指数阶段搭好了舞台。</p><p>过去几轮 VR 炒作周期给我们的教训是:别抱太高期望。VR 的 S 曲线爆发可能还要好多年,也可能永远不会到来。但过去苹果发布会给我们的教训是:别赌苹果会输。而苹果这次押的是:Vision Pro 可能会成为像初代 iPhone 那样的种子——一个能把新的 S 曲线推入高速档的创新平台。<a href="#footnote-4-10470">4</a></p><h2 id="vision-pro-v2-–-v10" tabindex="-1"><strong>Vision Pro,V2 – V10</strong> <a class="header-anchor" href="#vision-pro-v2-–-v10" aria-label="Permalink to &quot;**Vision Pro,V2 – V10**&quot;">​</a></h2><p>要让人们经常使用一款科技产品,收益必须大于成本。眼下 Vision Pro 的收益大概还低于成本。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2024/02/Scale-1.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>我已经付了钱,这去掉了其中一项成本,但从长远看,我究竟会在多大程度上选它而不是电脑,<em>仍然</em>是个问题。从这个角度说,AVP 目前可能更像那些<a href="https://www.seeclearfield.com/assets/images/blogs/bag-phone.jpg" target="_blank" rel="noreferrer">早期的大哥大</a>——得拎着一个手提箱到处跑——而不是初代 iPhone。如果手机唯一的形态就是拴在一个手提箱上,你会去买一部吗?也许会,但真的很难说。</p><p>要让 VR 实现大规模普及,好的地方得更好,坏的地方得没那么坏。这两条路径都不难想象。</p><p>操作系统每年都会变好。目前唯一的手势是两指捏合。以后会加更多。最终,我们的手指也许能做出几十种手势,每种对应不同的命令,就像今天的键盘快捷键。当你花十分钟精心布置好一套窗口配置,你将能保存(并分享)它。</p><p>虚拟化身会从「恐怖谷」进化到与你本人的脸难以区分。当你进入沉浸式环境时,你现在只能看到自己的双手。未来,你将能指定其他物体保持可见(比如一个咖啡杯)。你周围的环境会从目前的 6 个选项扩展到几百个,其中包括各种美妙的奇幻世界,而且它们将是可交互的,允许你改变天气之类的东西。</p><p>硬件会不断变小、变舒适。分辨率和帧率会变得跟延迟一样先进。电池会好得多。从外面看的样子也会好得多:对屋里的人来说,头显会变得完全透明。(我个人的幻想:计算机本身变成可拆卸的,让头显成为一副轻巧、时髦、酷炫的面罩。计算机和电池合在一起,大约智能手机大小。如果你不想要连线,可以把它扣在面罩的后脑勺位置,但大多数人会更希望重量放在头以外的地方。这个计算机/电池方块本身也带屏幕,可以作为智能手机使用,方便你在摘下面罩时也能干点什么。面罩会整齐地折叠到这个方块上,让整个东西变成一件紧凑的物品。)</p><p>最后,内容、应用和体验的数量会翻上 1000 倍,就像 2008 年到今天应用商店里的 app 数量那样。会出现琳琅满目的沉浸式游戏和娱乐。人们看体育比赛时,可以从场内、场边、看台、或者高空俯视等各种视角中随意切换——身边坐着朋友,大家可以看着彼此聊天,感觉就跟真人在一起没什么两样。流行歌星开演唱会时,现场 5 万人,虚拟观众 500 万人。健身会变得有趣、互动、社交化。最好的老师和教练能触达数百万人。厉害的 AI 老师能触达数十亿人。距离将不复存在,人们无论身在何处都可以和所爱之人享受高质量的相处时光。今天那些做梦都不敢想环游世界的人,以后能在地球上任何角落享受身临其境的体验。当然,我 2024 年这点可笑的想象力,就跟大哥大时代的人预测不了 Uber、TikTok 或 Tinder 一样,连表面都摸不到。</p><p>随着时间推移,价格会降下来,一些公司会把头显做得白菜价,就像今天的智能手机一样。随着价值主张越来越有吸引力,越来越多人会拥有它,这又会强化社交属性、消除任何污名。大规模普及看起来是个非常现实的未来可能性。</p><p>我知道你们很多人在想什么:一个人人都戴着 VR 头显(或面罩、眼镜、隐形眼镜)的世界,听着挺反乌托邦、挺 <a href="https://waitbutwhy.com/wp-content/uploads/2024/02/goldblum.jpg" target="_blank" rel="noreferrer">恶心的</a>。而且没错,说这话的人当年觉得《瓦力》里那群坐在移动椅子上目光呆滞的人所在的世界看起来是个宜居的好地方——但我还是很兴奋。</p><h2 id="好了-我现在能把这玩意儿从脸上摘下来了吗" tabindex="-1">好了,我现在能把这玩意儿从脸上摘下来了吗? <a class="header-anchor" href="#好了-我现在能把这玩意儿从脸上摘下来了吗" aria-label="Permalink to &quot;好了,我现在能把这玩意儿从脸上摘下来了吗?&quot;">​</a></h2><p><strong>接下来可以读:</strong></p><p><a href="https://waitbutwhy.com/2017/04/neuralink.html" target="_blank" rel="noreferrer">一篇关于比 VR 更劲爆的技术的文章</a></p><p><a href="https://waitbutwhy.com/2016/03/cryonics.html" target="_blank" rel="noreferrer">一篇关于另一项比 VR 更劲爆的技术的文章</a></p><h2 id="一篇关于第三项比-vr-更劲爆的技术的文章" tabindex="-1"><a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">一篇关于第三项比 VR 更劲爆的技术的文章</a> <a class="header-anchor" href="#一篇关于第三项比-vr-更劲爆的技术的文章" aria-label="Permalink to &quot;[一篇关于第三项比 VR 更劲爆的技术的文章](https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会通知你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>当你在新环境里使用 Quest 2 时,必须手动向头显展示你即将使用的开放空间的边界。这在更新的 Quest 3 上就不需要了,它会自动扫描出空间。<a href="#note-1-10470">↩</a></p></li><li><p>「虚拟现实 (Virtual Reality)」传统上指的是完全沉浸式的头显体验。「增强现实 (Augmented Reality)」则是你看到周围真实世界的同时,里面叠加了虚拟元素。<a href="#note-2-10470">↩</a></p></li><li><p>我们太习惯手机了,以至于忘了它们有多疯狂地酷。我可以拿起我的小长方形,瞬间联系上你——不管你在这颗<em>星球</em>的哪个角落。<a href="#note-3-10470">↩</a></p></li><li><p>如果真是这样,未拆封的第一代 Vision Pro 会在 2060 年被拍出天价。就这么一说……<a href="#note-4-10470">↩</a></p></li></ol><hr><ol><li><p>图片来源:<a href="https://www.apple.com/newsroom/2023/06/introducing-apple-vision-pro/" target="_blank" rel="noreferrer">Apple</a><a href="#note2-1-10470">↩</a></p></li><li><p>图片来源:<a href="https://www.apple.com/newsroom/2024/02/apple-announces-more-than-600-new-apps-built-for-apple-vision-pro/" target="_blank" rel="noreferrer">Apple</a><a href="#note2-2-10470">↩</a></p></li><li><p><a href="https://www.frontiersin.org/journals/psychology/articles/10.3389/fpsyg.2017.01792/full" target="_blank" rel="noreferrer">图片来源</a><a href="#note2-3-10470">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2024/02/vision-pro.html&amp;description=All%20My%20Thoughts%20After%2040%20Hours%20in%20the%20Vision%20Pro" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p>',113)])])}const T=r(V,[["render",d]]);export{S as __pageData,T as default};
